pipeline.evaluate:
(() => {
  const items = [];
  document.querySelectorAll('.search-result').forEach(result => {
    const titleEl = result.querySelector('.result-link a');
    if (titleEl) {
      items.push({
        title: titleEl.textContent.trim(),
        url: 'https://stackoverflow.com' + titleEl.getAttribute('href')
      });
    }
  });
  return items;
})()
